//! Pure data types for the config TUI (Elm-style Model layer).

use grove_core::{ExploreConfig, Provider, Steering};

/// Which field currently holds focus.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Field {
    Provider,
    Url,
    Model,
    Mode,
    Tap,
    Tools,
}

impl Field {
    /// Advance focus to the next field (wraps around).
    pub fn next(self) -> Self {
        match self {
            Field::Provider => Field::Url,
            Field::Url => Field::Model,
            Field::Model => Field::Mode,
            Field::Mode => Field::Tap,
            Field::Tap => Field::Tools,
            Field::Tools => Field::Provider,
        }
    }

    /// Retreat focus to the previous field (wraps around).
    pub fn prev(self) -> Self {
        match self {
            Field::Provider => Field::Tools,
            Field::Url => Field::Provider,
            Field::Model => Field::Url,
            Field::Mode => Field::Model,
            Field::Tap => Field::Mode,
            Field::Tools => Field::Tap,
        }
    }
}

/// High-level actions that the event loop dispatches on.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Action {
    /// Validate and persist the config, then exit.
    Save,
    /// Exit without touching the on-disk config.
    Quit,
    /// Fetch the provider's model list (blocking IO the loop performs, then feeds
    /// back a [`Msg::ModelListFetched`] / [`Msg::ModelFetchError`]).
    FetchModels,
}

/// Application-level messages produced by the event loop and consumed by
/// `update()`.
#[derive(Debug, Clone)]
pub enum Msg {
    /// Focus moves forward.
    TabNext,
    /// Focus moves backward.
    TabPrev,
    /// Provider list — up/prev.
    ProviderUp,
    /// Provider list — down/next.
    ProviderDown,
    /// URL field — a printable character was typed.
    UrlChar(char),
    /// URL field — backspace.
    UrlBackspace,
    /// Model field — a printable character was typed.
    ModelChar(char),
    /// Model field — backspace.
    ModelBackspace,
    /// Model field — open the auto-discovery dropdown (triggers a fetch).
    ModelDropdownOpen,
    /// Model dropdown — move the highlight up/down.
    ModelUp,
    ModelDown,
    /// Model dropdown — accept the highlighted entry.
    ModelSelect,
    /// Model dropdown — close without selecting.
    ModelClose,
    /// Model dropdown — the fetched model ids arrived.
    ModelListFetched(Vec<String>),
    /// Model dropdown — the fetch failed (message shown, free-text still works).
    ModelFetchError(String),
    /// Mode list — up/prev.
    ModeUp,
    /// Mode list — down/next.
    ModeDown,
    /// Tools list — cursor up.
    ToolsUp,
    /// Tools list — cursor down.
    ToolsDown,
    /// Tools list — toggle selected tool.
    ToolsToggle,
    /// Tools list — a character typed into the add-tool buffer.
    ToolsAddChar(char),
    /// Tools list — backspace in the add-tool buffer.
    ToolsAddBackspace,
    /// Tools list — confirm add-tool buffer as a new tool entry.
    ToolsAddConfirm,
    /// Tap field — toggle session tracing on/off.
    TapToggle,
    /// User pressed save.
    Save,
    /// User pressed quit/cancel.
    Quit,
}

/// Default base URLs for each provider.
pub const OLLAMA_DEFAULT_URL: &str = "http://localhost:11434/v1";
pub const LLAMACPP_DEFAULT_URL: &str = "http://localhost:8080/v1";

/// The full TUI state.
#[derive(Debug, Clone)]
pub struct App {
    /// Index into `Provider::LEGAL`.
    pub provider: usize,
    /// The base URL currently in the text buffer.
    pub base_url: String,
    /// The model currently in the text buffer.
    pub model: String,
    /// Index into `Mode::LEGAL`.
    pub mode: usize,
    /// `(name, selected)` pairs.
    pub tools: Vec<(String, bool)>,
    /// Cursor position in the tools list.
    pub tool_cursor: usize,
    /// Buffer for a new tool name being typed.
    pub add_tool_buf: String,
    /// Which field is focused.
    pub focus: Field,
    /// Session tracing to `.grove/traces/` (browse with `grove tap`).
    pub tap: bool,
    /// Trace-session retention, carried through unchanged (edited via config file).
    pub trace_retain: u32,
    /// Whether the model auto-discovery dropdown is open.
    pub model_dropdown: bool,
    /// Model ids fetched from the provider's `/models` listing.
    pub model_list: Vec<String>,
    /// Highlighted entry within the filtered dropdown.
    pub model_cursor: usize,
    /// Transient dropdown status (fetching / error / empty), shown in the list.
    pub model_status: Option<String>,
    /// `true` after the user has manually edited `base_url`, preventing
    /// provider-switch from clobbering a custom endpoint.
    pub dirty_url: bool,
    /// Last validation error to display in the status bar.
    pub last_error: Option<String>,
}

impl Default for App {
    fn default() -> Self {
        App::from_config(ExploreConfig::default()).reset_dirty()
    }
}

impl App {
    /// Pre-populate TUI state from an existing [`ExploreConfig`].
    ///
    /// `dirty_url` is set to `true` so that a provider switch does **not**
    /// clobber a custom endpoint the user previously saved.
    pub fn from_config(cfg: ExploreConfig) -> Self {
        let provider = match cfg.provider {
            Provider::Ollama => 0,
            Provider::LlamaCpp => 1,
        };
        let mode = match cfg.steering {
            Steering::Standard => 0,
            Steering::Balanced => 1,
            Steering::Aggressive => 2,
        };
        // Existing tools are shown as selected; no unselected entries from load.
        let tools = cfg.allowed_tools.into_iter().map(|t| (t, true)).collect();
        Self {
            provider,
            base_url: cfg.base_url,
            model: cfg.model,
            mode,
            tools,
            tool_cursor: 0,
            add_tool_buf: String::new(),
            focus: Field::Provider,
            tap: cfg.tap,
            trace_retain: cfg.trace_retain,
            model_dropdown: false,
            model_list: Vec::new(),
            model_cursor: 0,
            model_status: None,
            dirty_url: true, // loaded URL is custom; don't clobber on provider switch
            last_error: None,
        }
    }

    /// The default-construction path: same as `from_config(default)` but with
    /// `dirty_url` cleared so provider switches refresh the URL default.
    fn reset_dirty(mut self) -> Self {
        self.dirty_url = false;
        self
    }

    /// The dropdown entries matching the current model buffer (case-insensitive
    /// substring). An empty buffer shows the full list.
    pub fn model_filtered(&self) -> Vec<String> {
        let needle = self.model.to_lowercase();
        self.model_list
            .iter()
            .filter(|m| needle.is_empty() || m.to_lowercase().contains(&needle))
            .cloned()
            .collect()
    }

    /// Convert TUI state back to a validated [`ExploreConfig`].
    pub fn to_config(&self) -> anyhow::Result<ExploreConfig> {
        let provider = match self.provider {
            0 => Provider::Ollama,
            _ => Provider::LlamaCpp,
        };
        let steering = match self.mode {
            0 => Steering::Standard,
            1 => Steering::Balanced,
            _ => Steering::Aggressive,
        };
        let allowed_tools = self
            .tools
            .iter()
            .filter(|(_, sel)| *sel)
            .map(|(name, _)| name.clone())
            .collect();
        let cfg = ExploreConfig {
            provider,
            base_url: self.base_url.clone(),
            model: self.model.clone(),
            steering,
            allowed_tools,
            tap: self.tap,
            trace_retain: self.trace_retain,
        };
        cfg.validate()?;
        Ok(cfg)
    }
}

//! Ratatui rendering for the config TUI (Elm-style View layer).

use ratatui::{
    layout::{Constraint, Direction, Layout, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Clear, List, ListItem, ListState, Paragraph},
    Frame,
};

use crate::config_tui::model::{App, Field};

/// Colours.
const FOCUSED: Color = Color::Cyan;
const NORMAL: Color = Color::White;
const SELECTED: Color = Color::Green;
const DIM: Color = Color::DarkGray;

/// Mode descriptions shown alongside each mode entry.
const MODE_DESCS: &[&str] = &[
    "Standard   — merit-based, least intrusive",
    "Balanced   — plan-first steering",
    "Aggressive — coercive steering",
];

/// Render the full TUI frame.
pub fn view(app: &App, frame: &mut Frame) {
    let area = frame.area();

    // Outer chrome — shortcuts now live in the footer, not the title.
    let outer = Block::default()
        .borders(Borders::ALL)
        .title(" grove config — Explore Setup ");
    let inner = outer.inner(area);
    frame.render_widget(outer, area);

    // Vertical sections
    let rows = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(3), // Provider
            Constraint::Length(3), // Endpoint URL
            Constraint::Length(3), // Model
            Constraint::Length(5), // Mode (3 items + borders)
            Constraint::Length(3), // Tap
            Constraint::Min(4),    // Allowed Tools
            Constraint::Length(1), // Status bar
            Constraint::Length(1), // Footer shortcuts
        ])
        .split(inner);

    render_provider(app, frame, rows[0]);
    render_url(app, frame, rows[1]);
    render_model(app, frame, rows[2]);
    render_mode(app, frame, rows[3]);
    render_tap(app, frame, rows[4]);
    render_tools(app, frame, rows[5]);
    render_status(app, frame, rows[6]);
    render_footer(app, frame, rows[7]);

    // The model dropdown floats over the lower rows when open.
    if app.focus == Field::Model && app.model_dropdown {
        render_model_dropdown(app, frame, rows[2]);
    }
}

// ── Tap ─────────────────────────────────────────────────────────────────────

fn render_tap(app: &App, frame: &mut Frame, area: Rect) {
    let focused = app.focus == Field::Tap;
    let text = if app.tap {
        "☑ on — recording sessions to .grove/traces/  (browse: grove tap)"
    } else {
        "☐ off"
    };
    let fg = if focused {
        FOCUSED
    } else if app.tap {
        SELECTED
    } else {
        DIM
    };
    let para = Paragraph::new(text)
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_style(border_style(focused))
                .title(" Tap — trace LLM sessions (Space: toggle) "),
        )
        .style(Style::default().fg(fg));
    frame.render_widget(para, area);
}

// ── Provider ─────────────────────────────────────────────────────────────────

fn render_provider(app: &App, frame: &mut Frame, area: Rect) {
    let focused = app.focus == Field::Provider;
    let border_style = border_style(focused);

    let labels = &["Ollama", "Llama.cpp"];
    let items: Vec<ListItem> = labels
        .iter()
        .enumerate()
        .map(|(i, label)| {
            let style = if i == app.provider {
                Style::default().fg(SELECTED).add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(NORMAL)
            };
            ListItem::new(Line::from(Span::styled(*label, style)))
        })
        .collect();

    let list = List::new(items)
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_style(border_style)
                .title(" Provider (↑↓ to select) "),
        )
        .highlight_style(Style::default().fg(FOCUSED).add_modifier(Modifier::BOLD));

    let mut state = ListState::default();
    state.select(Some(app.provider));
    frame.render_stateful_widget(list, area, &mut state);
}

// ── Endpoint URL ──────────────────────────────────────────────────────────────

fn render_url(app: &App, frame: &mut Frame, area: Rect) {
    let focused = app.focus == Field::Url;
    let cursor_suffix = if focused { "█" } else { "" };
    let para = Paragraph::new(format!("{}{}", app.base_url, cursor_suffix))
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_style(border_style(focused))
                .title(" Endpoint URL "),
        )
        .style(Style::default().fg(if focused { FOCUSED } else { NORMAL }));
    frame.render_widget(para, area);
}

// ── Model ─────────────────────────────────────────────────────────────────────

fn render_model(app: &App, frame: &mut Frame, area: Rect) {
    let focused = app.focus == Field::Model;
    let cursor_suffix = if focused { "█" } else { "" };
    let title = if focused {
        " Model (↓ to pick from provider) "
    } else {
        " Model "
    };
    let para = Paragraph::new(format!("{}{}", app.model, cursor_suffix))
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_style(border_style(focused))
                .title(title),
        )
        .style(Style::default().fg(if focused { FOCUSED } else { NORMAL }));
    frame.render_widget(para, area);
}

/// The floating auto-discovery dropdown under the Model field.
fn render_model_dropdown(app: &App, frame: &mut Frame, model_area: Rect) {
    let filtered = app.model_filtered();
    let rows: Vec<ListItem> = if filtered.is_empty() {
        let msg = app
            .model_status
            .clone()
            .unwrap_or_else(|| "no matches — Esc to close".to_string());
        vec![ListItem::new(Line::from(Span::styled(msg, Style::default().fg(DIM))))]
    } else {
        filtered
            .iter()
            .map(|m| ListItem::new(Line::from(Span::styled(m.clone(), Style::default().fg(NORMAL)))))
            .collect()
    };

    // Height: entries (capped) + borders; width matches the model field.
    let shown = filtered.len().clamp(1, 8) as u16;
    let height = (shown + 2).clamp(3, model_area.height.saturating_add(10));
    let full = frame.area();
    let y = (model_area.y + model_area.height).min(full.height.saturating_sub(height));
    let popup = Rect {
        x: model_area.x + 1,
        y,
        width: model_area.width.saturating_sub(2),
        height,
    };

    let title = match &app.model_status {
        Some(s) => format!(" Models · {s} "),
        None => " Models (↑↓ select · type to filter · Enter · Esc) ".to_string(),
    };
    let list = List::new(rows)
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_style(Style::default().fg(FOCUSED))
                .title(title),
        )
        .highlight_style(Style::default().fg(FOCUSED).add_modifier(Modifier::BOLD))
        .highlight_symbol("▸ ");

    let mut state = ListState::default();
    if !filtered.is_empty() {
        state.select(Some(app.model_cursor.min(filtered.len() - 1)));
    }
    frame.render_widget(Clear, popup);
    frame.render_stateful_widget(list, popup, &mut state);
}

// ── Mode ──────────────────────────────────────────────────────────────────────

fn render_mode(app: &App, frame: &mut Frame, area: Rect) {
    let focused = app.focus == Field::Mode;
    let items: Vec<ListItem> = MODE_DESCS
        .iter()
        .enumerate()
        .map(|(i, desc)| {
            let style = if i == app.mode {
                Style::default().fg(SELECTED).add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(NORMAL)
            };
            ListItem::new(Line::from(Span::styled(*desc, style)))
        })
        .collect();

    let list = List::new(items)
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_style(border_style(focused))
                .title(" Mode (↑↓ to select) "),
        )
        .highlight_style(Style::default().fg(FOCUSED).add_modifier(Modifier::BOLD));

    let mut state = ListState::default();
    state.select(Some(app.mode));
    frame.render_stateful_widget(list, area, &mut state);
}

// ── Allowed Tools ─────────────────────────────────────────────────────────────

fn render_tools(app: &App, frame: &mut Frame, area: Rect) {
    let focused = app.focus == Field::Tools;

    // Split: tool list on left, add-tool input on right
    let cols = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([Constraint::Min(20), Constraint::Length(24)])
        .split(area);

    // Tool checklist
    let items: Vec<ListItem> = app
        .tools
        .iter()
        .enumerate()
        .map(|(i, (name, selected))| {
            let check = if *selected { "☑" } else { "☐" };
            let style = if focused && i == app.tool_cursor {
                Style::default().fg(FOCUSED).add_modifier(Modifier::BOLD)
            } else if *selected {
                Style::default().fg(SELECTED)
            } else {
                Style::default().fg(DIM)
            };
            ListItem::new(Line::from(Span::styled(format!("{check} {name}"), style)))
        })
        .collect();

    let list = List::new(items)
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_style(border_style(focused))
                .title(" Allowed Tools (Space: toggle) "),
        )
        .highlight_style(Style::default().fg(FOCUSED));

    let mut state = ListState::default();
    if focused && !app.tools.is_empty() {
        state.select(Some(app.tool_cursor));
    }
    frame.render_stateful_widget(list, cols[0], &mut state);

    // Add-tool buffer
    let cursor_suffix = if focused { "█" } else { "" };
    let add_para = Paragraph::new(format!("{}{}", app.add_tool_buf, cursor_suffix))
        .block(
            Block::default()
                .borders(Borders::ALL)
                .border_style(border_style(focused))
                .title(" + Add Tool (Enter) "),
        )
        .style(Style::default().fg(if focused { FOCUSED } else { DIM }));
    frame.render_widget(add_para, cols[1]);
}

// ── Status bar ────────────────────────────────────────────────────────────────

fn render_status(app: &App, frame: &mut Frame, area: Rect) {
    // Show the provider default-URL hint or the last error.
    let text = if let Some(ref err) = app.last_error {
        Span::styled(format!("✗ {err}"), Style::default().fg(Color::Red))
    } else {
        let hint = match app.provider {
            0 => "Provider: Ollama  ·  default http://localhost:11434/v1".to_string(),
            _ => "Provider: Llama.cpp  ·  default http://localhost:8080/v1".to_string(),
        };
        Span::styled(hint, Style::default().fg(DIM))
    };
    frame.render_widget(Paragraph::new(Line::from(text)), area);
}

// ── Footer shortcut bar ─────────────────────────────────────────────────────

fn render_footer(app: &App, frame: &mut Frame, area: Rect) {
    // Context-sensitive to the focused field; global keys always shown.
    let field_keys = match app.focus {
        Field::Provider => "↑↓ select provider",
        Field::Url => "type to edit URL",
        Field::Model if app.model_dropdown => "↑↓ pick · type filter · Enter select · Esc close",
        Field::Model => "type model · ↓ browse provider models",
        Field::Mode => "↑↓ select mode",
        Field::Tap => "Space toggle tracing",
        Field::Tools => "↑↓ move · Space toggle · type+Enter add",
    };
    let text = format!(" {field_keys}  │  Tab next · F2 save · Esc cancel ");
    let bar = Paragraph::new(Line::from(Span::styled(
        text,
        Style::default()
            .fg(Color::Black)
            .bg(FOCUSED)
            .add_modifier(Modifier::BOLD),
    )))
    .style(Style::default().bg(FOCUSED));
    frame.render_widget(bar, area);
}

// ── Helpers ───────────────────────────────────────────────────────────────────

fn border_style(focused: bool) -> Style {
    if focused {
        Style::default().fg(FOCUSED).add_modifier(Modifier::BOLD)
    } else {
        Style::default().fg(DIM)
    }
}

//! Pure state transitions for the config TUI (Elm-style Update layer).
//!
//! `update()` takes an `App` by mutable reference and a `Msg`, applies the
//! transition in place, and returns an optional `Action` when the event loop
//! should perform a side-effect (save, quit, or fetch the model list).

use crate::config_tui::model::{Action, App, Msg, LLAMACPP_DEFAULT_URL, OLLAMA_DEFAULT_URL};

/// Apply `msg` to `app`; return `Some(Action)` if the loop should act.
pub fn update(app: &mut App, msg: Msg) -> Option<Action> {
    match msg {
        Msg::TabNext => {
            app.model_dropdown = false;
            app.focus = app.focus.next();
            None
        }
        Msg::TabPrev => {
            app.model_dropdown = false;
            app.focus = app.focus.prev();
            None
        }

        // ── Provider ────────────────────────────────────────────────────────
        Msg::ProviderUp => {
            app.provider = app.provider.saturating_sub(1);
            apply_provider_default(app);
            None
        }
        Msg::ProviderDown => {
            app.provider = (app.provider + 1).min(1);
            apply_provider_default(app);
            None
        }

        // ── URL text buffer ──────────────────────────────────────────────────
        Msg::UrlChar(c) => {
            app.base_url.push(c);
            app.dirty_url = true;
            None
        }
        Msg::UrlBackspace => {
            app.base_url.pop();
            app.dirty_url = true;
            None
        }

        // ── Model text buffer + dropdown ─────────────────────────────────────
        Msg::ModelChar(c) => {
            app.model.push(c);
            app.model_cursor = 0; // re-filter from the top
            None
        }
        Msg::ModelBackspace => {
            app.model.pop();
            app.model_cursor = 0;
            None
        }
        Msg::ModelDropdownOpen => {
            app.model_dropdown = true;
            app.model_cursor = 0;
            app.model_status = Some("fetching models…".to_string());
            Some(Action::FetchModels)
        }
        Msg::ModelUp => {
            app.model_cursor = app.model_cursor.saturating_sub(1);
            None
        }
        Msg::ModelDown => {
            let last = app.model_filtered().len().saturating_sub(1);
            app.model_cursor = (app.model_cursor + 1).min(last);
            None
        }
        Msg::ModelSelect => {
            if let Some(pick) = app.model_filtered().get(app.model_cursor) {
                app.model = pick.clone();
            }
            app.model_dropdown = false;
            None
        }
        Msg::ModelClose => {
            app.model_dropdown = false;
            None
        }
        Msg::ModelListFetched(list) => {
            app.model_status = if list.is_empty() {
                Some("no models reported — type one".to_string())
            } else {
                None
            };
            app.model_list = list;
            app.model_cursor = 0;
            None
        }
        Msg::ModelFetchError(e) => {
            app.model_list.clear();
            app.model_status = Some(format!("fetch failed ({e}) — type a model"));
            None
        }

        // ── Mode ─────────────────────────────────────────────────────────────
        Msg::ModeUp => {
            app.mode = app.mode.saturating_sub(1);
            None
        }
        Msg::ModeDown => {
            app.mode = (app.mode + 1).min(2);
            None
        }

        // ── Tools ─────────────────────────────────────────────────────────────
        Msg::ToolsUp => {
            app.tool_cursor = app.tool_cursor.saturating_sub(1);
            None
        }
        Msg::ToolsDown => {
            if !app.tools.is_empty() {
                app.tool_cursor = (app.tool_cursor + 1).min(app.tools.len() - 1);
            }
            None
        }
        Msg::ToolsToggle => {
            if let Some(entry) = app.tools.get_mut(app.tool_cursor) {
                entry.1 = !entry.1;
            }
            None
        }
        Msg::ToolsAddChar(c) => {
            app.add_tool_buf.push(c);
            None
        }
        Msg::ToolsAddBackspace => {
            app.add_tool_buf.pop();
            None
        }
        Msg::ToolsAddConfirm => {
            let name = app.add_tool_buf.trim().to_string();
            if !name.is_empty() {
                app.tools.push((name, true));
                app.tool_cursor = app.tools.len() - 1;
                app.add_tool_buf.clear();
            }
            None
        }

        // ── Tap ───────────────────────────────────────────────────────────────
        Msg::TapToggle => {
            app.tap = !app.tap;
            None
        }

        // ── Terminal actions ──────────────────────────────────────────────────
        Msg::Save => Some(Action::Save),
        Msg::Quit => Some(Action::Quit),
    }
}

/// When the provider changes and the user has NOT manually edited the URL,
/// auto-fill the default endpoint for the new provider.
fn apply_provider_default(app: &mut App) {
    if app.dirty_url {
        return;
    }
    app.base_url = match app.provider {
        0 => OLLAMA_DEFAULT_URL.to_string(),
        _ => LLAMACPP_DEFAULT_URL.to_string(),
    };
}

// ─────────────────────────────────────────────────────────────────────────────
// Headless unit tests (no terminal required)
// ─────────────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;
    use crate::config_tui::model::Field;
    use grove_core::ExploreConfig;

    fn fresh() -> App {
        App::default()
    }

    // 1. Tab navigation — forward and backward, wrapping.
    #[test]
    fn tab_navigation_forward_wraps() {
        let mut app = fresh();
        assert_eq!(app.focus, Field::Provider);
        update(&mut app, Msg::TabNext);
        assert_eq!(app.focus, Field::Url);
        update(&mut app, Msg::TabNext);
        assert_eq!(app.focus, Field::Model);
        update(&mut app, Msg::TabNext);
        assert_eq!(app.focus, Field::Mode);
        update(&mut app, Msg::TabNext);
        assert_eq!(app.focus, Field::Tap);
        update(&mut app, Msg::TabNext);
        assert_eq!(app.focus, Field::Tools);
        update(&mut app, Msg::TabNext);
        assert_eq!(app.focus, Field::Provider); // wrapped
    }

    #[test]
    fn tab_navigation_backward_wraps() {
        let mut app = fresh();
        assert_eq!(app.focus, Field::Provider);
        update(&mut app, Msg::TabPrev);
        assert_eq!(app.focus, Field::Tools); // wrapped
    }

    #[test]
    fn tap_toggles() {
        let mut app = fresh();
        assert!(!app.tap);
        update(&mut app, Msg::TapToggle);
        assert!(app.tap, "tap flips on");
        update(&mut app, Msg::TapToggle);
        assert!(!app.tap, "tap flips off");
    }

    // 2. Provider selection drives URL default (unless URL is dirty).
    #[test]
    fn provider_switch_sets_url_default() {
        let mut app = fresh();
        assert_eq!(app.provider, 0); // Ollama
        assert_eq!(app.base_url, OLLAMA_DEFAULT_URL);

        update(&mut app, Msg::ProviderDown); // → LlamaCpp
        assert_eq!(app.provider, 1);
        assert_eq!(app.base_url, LLAMACPP_DEFAULT_URL);

        update(&mut app, Msg::ProviderUp); // → Ollama
        assert_eq!(app.provider, 0);
        assert_eq!(app.base_url, OLLAMA_DEFAULT_URL);
    }

    #[test]
    fn dirty_url_not_clobbered_on_provider_switch() {
        let mut app = fresh();
        // Manually edit URL → dirty_url = true
        update(&mut app, Msg::UrlChar('x'));
        let before = app.base_url.clone();
        // Switch provider
        update(&mut app, Msg::ProviderDown);
        assert_eq!(app.base_url, before, "dirty URL must not be overwritten");
    }

    // 3. Mode cycling.
    #[test]
    fn mode_cycling() {
        let mut app = fresh();
        assert_eq!(app.mode, 0); // Standard
        update(&mut app, Msg::ModeDown);
        assert_eq!(app.mode, 1); // Balanced
        update(&mut app, Msg::ModeDown);
        assert_eq!(app.mode, 2); // Aggressive
        update(&mut app, Msg::ModeDown); // already max
        assert_eq!(app.mode, 2);
        update(&mut app, Msg::ModeUp);
        assert_eq!(app.mode, 1);
    }

    // 4. Tool toggle.
    #[test]
    fn tool_toggle_flips_selected() {
        let mut app = fresh();
        // Default tools are all selected (true)
        assert!(app.tools[0].1, "first tool should start selected");
        update(&mut app, Msg::ToolsToggle);
        assert!(!app.tools[0].1, "should be deselected after toggle");
        update(&mut app, Msg::ToolsToggle);
        assert!(app.tools[0].1, "should be reselected after second toggle");
    }

    // 5. Model auto-discovery dropdown.
    #[test]
    fn model_dropdown_open_requests_fetch() {
        let mut app = fresh();
        let action = update(&mut app, Msg::ModelDropdownOpen);
        assert_eq!(action, Some(Action::FetchModels));
        assert!(app.model_dropdown, "dropdown is now open");
        assert!(app.model_status.is_some(), "shows a fetching status");
    }

    #[test]
    fn model_list_fetch_populates_and_select_sets_model() {
        let mut app = fresh();
        update(&mut app, Msg::ModelDropdownOpen);
        update(
            &mut app,
            Msg::ModelListFetched(vec!["qwen2.5-coder:7b".into(), "llama3:8b".into()]),
        );
        assert!(app.model_status.is_none(), "status cleared on non-empty list");
        // Filtering: typing narrows the list.
        app.model.clear();
        for c in "llama".chars() {
            update(&mut app, Msg::ModelChar(c));
        }
        assert_eq!(app.model_filtered(), vec!["llama3:8b".to_string()]);
        update(&mut app, Msg::ModelSelect);
        assert_eq!(app.model, "llama3:8b");
        assert!(!app.model_dropdown, "selecting closes the dropdown");
    }

    #[test]
    fn model_fetch_error_falls_back_to_free_text() {
        let mut app = fresh();
        update(&mut app, Msg::ModelDropdownOpen);
        update(&mut app, Msg::ModelFetchError("connection refused".into()));
        assert!(app.model_list.is_empty());
        assert!(app.model_status.as_deref().unwrap().contains("fetch failed"));
        // Free-text entry still works.
        update(&mut app, Msg::ModelChar('x'));
        assert!(app.model.ends_with('x'));
    }

    #[test]
    fn tab_closes_open_dropdown() {
        let mut app = fresh();
        app.model_dropdown = true;
        update(&mut app, Msg::TabNext);
        assert!(!app.model_dropdown, "moving focus closes the dropdown");
    }

    // 6. Save / quit actions.
    #[test]
    fn save_returns_action() {
        let mut app = fresh();
        let action = update(&mut app, Msg::Save);
        assert_eq!(action, Some(Action::Save));
    }

    #[test]
    fn quit_returns_action_without_mutation() {
        let mut app = fresh();
        let orig_url = app.base_url.clone();
        let action = update(&mut app, Msg::Quit);
        assert_eq!(action, Some(Action::Quit));
        assert_eq!(app.base_url, orig_url, "quit must not mutate state");
    }

    // 7. App::to_config() round-trip.
    #[test]
    fn to_config_round_trip() {
        let app = fresh();
        let cfg = app.to_config().expect("default App should produce a valid config");
        assert_eq!(cfg, ExploreConfig::default());
    }

    // 8. Empty required field fails validation.
    #[test]
    fn to_config_fails_on_blank_model() {
        let mut app = fresh();
        app.model.clear();
        let err = app.to_config().unwrap_err();
        assert!(err.to_string().contains("model"), "error should name the field: {err}");
    }

    #[test]
    fn to_config_fails_on_blank_url() {
        let mut app = fresh();
        app.base_url.clear();
        let err = app.to_config().unwrap_err();
        assert!(err.to_string().contains("base_url"), "error should name the field: {err}");
    }

    // 9. App::from_config() pre-populates all fields.
    #[test]
    fn from_config_pre_populates() {
        let cfg = ExploreConfig {
            provider: grove_core::Provider::LlamaCpp,
            base_url: "http://localhost:8080/v1".to_string(),
            model: "llama3".to_string(),
            steering: grove_core::Steering::Aggressive,
            allowed_tools: vec!["grove".to_string()],
            tap: true,
            trace_retain: 25,
        };
        let app = App::from_config(cfg.clone());
        assert_eq!(app.provider, 1, "LlamaCpp should map to index 1");
        assert_eq!(app.base_url, "http://localhost:8080/v1");
        assert_eq!(app.model, "llama3");
        assert_eq!(app.mode, 2, "Aggressive should map to index 2");
        assert_eq!(app.tools, vec![("grove".to_string(), true)]);
        assert_eq!(app.trace_retain, 25, "retention carried through unchanged");
        assert!(app.dirty_url, "loaded config must set dirty_url=true");

        // Round-trip back
        let back = app.to_config().unwrap();
        assert_eq!(back, cfg);
    }
}

//! Full-screen ratatui config TUI — entry point + event loop.
//!
//! `run(root, maybe_cfg)` is the only public surface. It:
//!   1. Fast-fails with a clear message when stdout is not a TTY.
//!   2. Enters the alternate screen in raw mode.
//!   3. Runs the Elm-style event loop (decode event → Msg → update → draw).
//!   4. Restores the terminal on **every** exit path (save, cancel, error).

pub mod model;
pub mod update;
pub mod view;

use std::io::{self, IsTerminal};
use std::path::Path;

use anyhow::Result;
use crossterm::{
    event::{self, Event, KeyCode, KeyEvent, KeyModifiers},
    execute,
    terminal::{disable_raw_mode, enable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen},
};
use ratatui::{backend::CrosstermBackend, Terminal};

use grove_core::ExploreConfig;

use model::{Action, App, Field, Msg};

/// Launch the config TUI.
///
/// * `root` — project root used by [`ExploreConfig::save`].
/// * `existing` — pre-populated config loaded by the caller; `None` for defaults.
///
/// Returns `Ok(())` on save or cancel. Returns an error for I/O failures and
/// (importantly) for non-TTY environments.
pub fn run(root: &Path, existing: Option<ExploreConfig>) -> Result<()> {
    // ── Non-TTY guard ────────────────────────────────────────────────────────
    if !io::stdout().is_terminal() {
        anyhow::bail!(
            "`grove config` requires an interactive terminal — \
             pipe output or redirect detected. \
             Use `grove config` in a real terminal session."
        );
    }

    // ── Initialise TUI state ─────────────────────────────────────────────────
    let mut app = match existing {
        Some(cfg) => App::from_config(cfg),
        None => App::default(),
    };

    // ── Set up terminal ──────────────────────────────────────────────────────
    enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(stdout, EnterAlternateScreen)?;
    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;

    // ── Event loop ───────────────────────────────────────────────────────────
    let result = event_loop(&mut terminal, &mut app, root);

    // ── Restore terminal — on ALL exit paths ─────────────────────────────────
    disable_raw_mode().ok();
    execute!(terminal.backend_mut(), LeaveAlternateScreen).ok();
    terminal.show_cursor().ok();

    result
}

fn event_loop(
    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
    app: &mut App,
    root: &Path,
) -> Result<()> {
    loop {
        terminal.draw(|f| view::view(app, f))?;

        let event = event::read()?;
        let Some(msg) = translate_event(app, event) else {
            continue;
        };
        match update::update(app, msg) {
            Some(Action::Save) => match app.to_config() {
                Ok(cfg) => {
                    cfg.save(root)?;
                    return Ok(());
                }
                Err(e) => {
                    // Stay in the TUI; show the error in the status bar.
                    app.last_error = Some(e.to_string());
                }
            },
            Some(Action::Quit) => return Ok(()),
            Some(Action::FetchModels) => fetch_models(app),
            None => {
                // Clear a previous error whenever the user types.
                app.last_error = None;
            }
        }
    }
}

/// Perform the blocking model-list fetch and feed the result back as a `Msg`.
/// Only `base_url` matters to the provider's `/models` listing.
fn fetch_models(app: &mut App) {
    let cfg = ExploreConfig {
        base_url: app.base_url.clone(),
        model: app.model.clone(),
        ..ExploreConfig::default()
    };
    let msg = match grove_core::explore::list_models(&cfg) {
        Ok(list) => Msg::ModelListFetched(list),
        Err(e) => Msg::ModelFetchError(e),
    };
    update::update(app, msg);
}

/// Translate a crossterm `Event` into an optional `Msg`, taking the current
/// focus field into account so field-specific key bindings apply only when
/// that field is active.
fn translate_event(app: &App, event: Event) -> Option<Msg> {
    let Event::Key(KeyEvent { code, modifiers, .. }) = event else {
        return None;
    };

    // Ctrl-C is a universal quit.
    if code == KeyCode::Char('c') && modifiers.contains(KeyModifiers::CONTROL) {
        return Some(Msg::Quit);
    }

    // When the model dropdown is open, keys drive the picker (so Esc closes it
    // rather than quitting, and typing filters).
    if app.focus == Field::Model && app.model_dropdown {
        return match code {
            KeyCode::Tab => Some(Msg::TabNext),
            KeyCode::BackTab => Some(Msg::TabPrev),
            KeyCode::Up => Some(Msg::ModelUp),
            KeyCode::Down => Some(Msg::ModelDown),
            KeyCode::Enter => Some(Msg::ModelSelect),
            KeyCode::Esc => Some(Msg::ModelClose),
            KeyCode::Backspace => Some(Msg::ModelBackspace),
            KeyCode::Char(c) => Some(Msg::ModelChar(c)),
            _ => None,
        };
    }

    // Global bindings that apply in any field.
    match code {
        KeyCode::Tab => return Some(Msg::TabNext),
        KeyCode::BackTab => return Some(Msg::TabPrev),
        KeyCode::F(2) => return Some(Msg::Save),
        KeyCode::Esc => return Some(Msg::Quit),
        KeyCode::Char('s')
            if modifiers.is_empty()
                && app.focus != Field::Url
                && app.focus != Field::Model
                && app.focus != Field::Tools =>
        {
            return Some(Msg::Save);
        }
        KeyCode::Char('q')
            if modifiers.is_empty()
                && app.focus != Field::Url
                && app.focus != Field::Model
                && app.focus != Field::Tools =>
        {
            return Some(Msg::Quit);
        }
        _ => {}
    }

    // Field-specific bindings.
    match app.focus {
        Field::Provider => match code {
            KeyCode::Up | KeyCode::Char('k') => Some(Msg::ProviderUp),
            KeyCode::Down | KeyCode::Char('j') => Some(Msg::ProviderDown),
            _ => None,
        },
        Field::Url => match code {
            KeyCode::Char(c) => Some(Msg::UrlChar(c)),
            KeyCode::Backspace => Some(Msg::UrlBackspace),
            _ => None,
        },
        Field::Model => match code {
            // Down opens the auto-discovery dropdown (and triggers a fetch).
            KeyCode::Down => Some(Msg::ModelDropdownOpen),
            KeyCode::Char(c) => Some(Msg::ModelChar(c)),
            KeyCode::Backspace => Some(Msg::ModelBackspace),
            _ => None,
        },
        Field::Mode => match code {
            KeyCode::Up | KeyCode::Char('k') => Some(Msg::ModeUp),
            KeyCode::Down | KeyCode::Char('j') => Some(Msg::ModeDown),
            _ => None,
        },
        Field::Tap => match code {
            KeyCode::Char(' ') | KeyCode::Enter => Some(Msg::TapToggle),
            _ => None,
        },
        Field::Tools => match code {
            KeyCode::Up | KeyCode::Char('k') => Some(Msg::ToolsUp),
            KeyCode::Down | KeyCode::Char('j') => Some(Msg::ToolsDown),
            KeyCode::Char(' ') => Some(Msg::ToolsToggle),
            KeyCode::Enter => Some(Msg::ToolsAddConfirm),
            KeyCode::Backspace => Some(Msg::ToolsAddBackspace),
            KeyCode::Char(c) => Some(Msg::ToolsAddChar(c)),
            _ => None,
        },
    }
}

